import torch
from torchvision import models, transforms
from PIL import Image
import io
import json
import base64
from flask import Flask, request, jsonify

app = Flask(__name__)

# Load pre-trained model and weights
model = models.resnet50(pretrained=True)
model.eval()

def classify_image(image_bytes):
    image = Image.open(io.BytesIO(base64.b64decode(image_bytes)))
    transform = transforms.Compose([
        transforms.Resize(256),
        transforms.CenterCrop(224),
        transforms.ToTensor(),
        transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
    ])
    image = transform(image)
    output = model(image.unsqueeze(0))
    _, predicted_class = torch.max(output, dim=1)
    confidence_score = torch.nn.functional.softmax(output, dim=1)[0][predicted_class].item()
    return predicted_class.item(), confidence_score

@app.route('/classify', methods=['POST'])
def classify():
    image_bytes = request.json['image']
    class_id, confidence_score = classify_image(image_bytes)
    classes = {
        0: 'class_0',
        1: 'class_1',
        # Add more classes here
    }
    return jsonify({'class': classes[class_id], 'confidence_score': confidence_score})

if __name__ == '__main__':
    app.run(debug=True)